21	const API_BASE = import.meta.env.VITE_API_BASE ?? "";
22	
23	export class BayesApiError extends Error {
24	  constructor(
25	    public status: number,
26	    public code: string,
27	    public details: Record<string, unknown> = {},
28	  ) {
29	    super(`${code}: ${status}`);
30	    this.name = "BayesApiError";
31	  }
32	}
33	
34	export interface NormalizedMarketListFilters {
35	  status?: string;
36	  includeResolved?: true;
37	}
38	
39	async function request<T>(
40	  path: string,
41	  options: RequestInit = {},
42	  session?: Session,
43	): Promise<T> {
44	  const headers: Record<string, string> = {
45	    ...(options.headers as Record<string, string>),
46	  };
47	
48	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
49	    headers["Content-Type"] = "application/json";
50	  }
51	
52	  if (session?.agentId) {
53	    headers["X-Bayes-Agent-Id"] = session.agentId;
54	  }
55	
56	  const res = await fetch(`${API_BASE}${path}`, {
57	    ...options,
58	    headers,
59	  });
60	
61	  const body = await res.json();
62	
63	  if (!res.ok) {
64	    const err = body as ApiError;
65	    throw new BayesApiError(
66	      res.status,
67	      err.error?.code ?? "unknown_error",
68	      err.error?.details ?? {},
69	    );
70	  }
71	
72	  return body as T;
73	}
74	
75	export function normalizeMarketListFilters(
76	  filters?: MarketListFilterInput,
77	): NormalizedMarketListFilters {
78	  const status = typeof filters === "string"
79	    ? filters
80	    : filters?.status;
81	  const includeResolved = (
82	    typeof filters !== "string"
83	    && filters?.includeResolved === true
84	  ) || status === "resolved";
85	
86	  return {
87	    ...(status ? { status } : {}),
88	    ...(includeResolved ? { includeResolved: true } : {}),
89	  };
90	}
91	
92	function serializeMarketListFilters(filters?: MarketListFilterInput): string {
93	  const normalizedFilters = normalizeMarketListFilters(filters);
94	  const params = new URLSearchParams();
95	
96	  if (normalizedFilters.status) {
97	    params.set("status", normalizedFilters.status);
98	  }
99	
100	  if (normalizedFilters.includeResolved) {
101	    params.set("include_resolved", "true");
102	  }
103	
104	  const queryString = params.toString();
105	  return queryString ? `?${queryString}` : "";
106	}
107	
108	export function listMarkets(
109	  filters?: MarketListFilterInput,
110	): Promise<MarketListResponse> {
111	  return request<MarketListResponse>(`/v1/markets${serializeMarketListFilters(filters)}`);
112	}
113	
114	export interface CreateMarketPayload {
115	  title: string;
116	  description: string;
117	  outcomes: Array<{ id: string; name: string }>;
118	  expires_at: string;
119	  liquidity?: number;
120	}
121	
122	export function createMarket(
123	  payload: CreateMarketPayload,
124	  session?: Session,
125	): Promise<MarketDetailResponse> {
126	  return request<MarketDetailResponse>(`/v1/markets`, {
127	    method: "POST",
128	    body: JSON.stringify(payload),
129	  }, session);
130	}
131	
132	export function getMarket(
133	  marketId: string,
134	): Promise<MarketDetailResponse> {
135	  return request<MarketDetailResponse>(`/v1/markets/${encodeURIComponent(marketId)}`);
136	}
137	
138	function joinUrlPath(basePath: string, path: string): string {
139	  const normalizedBase = basePath === "/" ? "" : basePath.replace(/\/$/, "");
140	  const normalizedPath = path.startsWith("/") ? path : `/${path}`;
141	  return `${normalizedBase}${normalizedPath}`;
142	}
143	
144	export function getMarketPricesWebSocketUrl(marketId: string): string {
145	  const baseUrl = API_BASE
146	    ? new URL(API_BASE, window.location.origin)
147	    : new URL(window.location.origin);
148	  const socketUrl = new URL(baseUrl.toString());
149	  socketUrl.protocol = socketUrl.protocol === "https:" ? "wss:" : "ws:";
150	  socketUrl.pathname = joinUrlPath(
151	    socketUrl.pathname,
152	    `/ws/markets/${encodeURIComponent(marketId)}/prices`,
153	  );
154	  socketUrl.search = "";
155	  socketUrl.hash = "";
156	  return socketUrl.toString();
157	}
158	
159	export function getMarketPreview(
160	  marketId: string,
161	): Promise<MarketPreviewResponse> {
162	  return request<MarketPreviewResponse>(`/v1/markets/${encodeURIComponent(marketId)}/meta`);
163	}
164	
165	export function getMarketEvents(
166	  marketId: string,
167	  opts: { fromSeq?: number; limit?: number } = {},
168	): Promise<MarketEventsResponse> {
169	  const params = new URLSearchParams();
170	  if (opts.fromSeq != null) params.set("fromSeq", String(opts.fromSeq));
171	  if (opts.limit != null) params.set("limit", String(opts.limit));
172	  const qs = params.toString();
173	  return request<MarketEventsResponse>(
174	    `/v1/markets/${encodeURIComponent(marketId)}/events${qs ? `?${qs}` : ""}`,
175	  );
176	}
177	
178	export function getMarketComments(
179	  marketId: string,
180	  opts: { fromSeq?: number; limit?: number } = {},
181	): Promise<MarketCommentsResponse> {
182	  const params = new URLSearchParams();
183	  if (opts.fromSeq != null) params.set("fromSeq", String(opts.fromSeq));
184	  if (opts.limit != null) params.set("limit", String(opts.limit));
185	  const qs = params.toString();
